define("local_datagrading/inline_grader",["core/ajax","core/notification","core/str"],(function(Ajax,Notification,Str){const DEBOUNCE_MS=800;const debounceTimers=new Map();const init=(cmid,contextid)=>{Str.get_strings([{key:"savinggrade",component:"local_datagrading"},{key:"graded",component:"local_datagrading"},{key:"errorsavegrade",component:"local_datagrading"},{key:"gradingprogress",component:"local_datagrading"}]).then(([savingStr,gradedStr,errorStr,progressStr])=>{wireGradeInputs(cmid,savingStr,gradedStr,errorStr);wireFeedbackAreas(cmid,savingStr,gradedStr,errorStr);wireReleaseControls(cmid);wireReleaseAllButton(cmid);return;}).catch(Notification.exception);};const wireGradeInputs=(cmid,savingStr,gradedStr,errorStr)=>{document.querySelectorAll("[data-gradeentry-field]").forEach(input=>{input.addEventListener("input",()=>{const recordid=parseInt(input.dataset.recordid,10);clearTimeout(debounceTimers.get(recordid));debounceTimers.set(recordid,setTimeout(()=>{const feedback=getFeedbackFor(recordid);triggerSave(cmid,input,input.dataset.fieldid,input.value,feedback,savingStr,gradedStr,errorStr);},DEBOUNCE_MS));});input.addEventListener("blur",()=>{const recordid=parseInt(input.dataset.recordid,10);clearTimeout(debounceTimers.get(recordid));const feedback=getFeedbackFor(recordid);triggerSave(cmid,input,input.dataset.fieldid,input.value,feedback,savingStr,gradedStr,errorStr);});});};const wireFeedbackAreas=(cmid,savingStr,gradedStr,errorStr)=>{document.querySelectorAll("[data-gradeentry-feedback]").forEach(textarea=>{textarea.addEventListener("blur",()=>{const gradeInput=getGradeInputFor(textarea.dataset.recordid);if(!gradeInput||gradeInput.value===""){return;}triggerSave(cmid,gradeInput,gradeInput.dataset.fieldid,gradeInput.value,textarea.value,savingStr,gradedStr,errorStr);});});};const wireReleaseControls=(cmid)=>{document.querySelectorAll("[data-gradeentry-release]").forEach(checkbox=>{checkbox.addEventListener("change",()=>{const recordid=parseInt(checkbox.dataset.recordid,10);Ajax.call([{methodname:"local_datagrading_release_grades",args:{cmid,recordids:[recordid]},done:()=>{updateReleasedLabel(checkbox,checkbox.checked);},fail:Notification.exception}]);});});};const wireReleaseAllButton=(cmid)=>{const btn=document.getElementById("local-datagrading-release-all");if(!btn){return;}btn.addEventListener("click",()=>{btn.disabled=true;Ajax.call([{methodname:"local_datagrading_release_grades",args:{cmid,recordids:[]},done:(result)=>{btn.disabled=false;document.querySelectorAll("[data-gradeentry-release]").forEach(cb=>{cb.checked=true;updateReleasedLabel(cb,true);});const progressText=document.getElementById("local-datagrading-progress-text");if(progressText){const original=progressText.textContent;progressText.textContent=result.released+" grades released";setTimeout(()=>{progressText.textContent=original;},3000);}},fail:(ex)=>{btn.disabled=false;Notification.exception(ex);}}]);});};const triggerSave=(cmid,gradeInput,fieldid,gradeValue,feedback,savingStr,gradedStr,errorStr)=>{const recordid=parseInt(gradeInput.dataset.recordid,10);const status=getStatusFor(recordid);setStatus(status,"saving",savingStr);Ajax.call([{methodname:"local_datagrading_save_grade",args:{cmid,recordid,fieldid:parseInt(fieldid,10),grade:parseFloat(gradeValue),feedback:feedback||""},done:(result)=>{setStatus(status,"saved",gradedStr);updateProgressBar(result.graded,result.total);},fail:(ex)=>{setStatus(status,"error",errorStr);Notification.exception(ex);}}]);};const getGradeInputFor=(recordid)=>document.querySelector(`[data-gradeentry-field][data-recordid="${recordid}"]`);const getFeedbackFor=(recordid)=>{const el=document.querySelector(`[data-gradeentry-feedback][data-recordid="${recordid}"]`);return el?el.value:"";};const getStatusFor=(recordid)=>document.querySelector(`[data-gradeentry-status][data-recordid="${recordid}"]`);const setStatus=(el,state,text)=>{if(!el){return;}el.textContent=text;el.className="gradeentry-status gradeentry-status--"+state;};const updateReleasedLabel=(checkbox,isReleased)=>{const label=checkbox.closest(".gradeentry-release-group")?.querySelector(".gradeentry-release-label");if(!label){return;}label.textContent=isReleased?label.dataset.releasedText:label.dataset.unreleasedText;};const updateProgressBar=(graded,total)=>{const bar=document.getElementById("local-datagrading-progress");if(!bar){return;}bar.dataset.graded=graded;bar.dataset.total=total;const text=document.getElementById("local-datagrading-progress-text");if(text){text.textContent=text.textContent.replace(/\d+\s*\/\s*\d+/,graded+" / "+total);}};return{init};}));
